import sys
import argparse
import boto3

def main():
    parser = argparse.ArgumentParser(description="Manage SNS subscriptions (https endpoints).")
    parser.add_argument("--topic-arn", required=True, help="SNS Topic ARN")
    parser.add_argument("--region", default=None, help="AWS region (optional)")
